with:
  # Build sentence with main subject facts first, connected with relative clauses
      sentence = main_phrases[0]
      for phrase in main_phrases[1:]:
          sentence += ", and " + phrase

      # Add related information with appropriate connectors
      if related_subjects:
          for rel_subject, rel_phrases in related_subjects.items():
              # Find which predicate connects this subject to the main subject
              connector = "which is"
              connection_found = False

              for triple in triples:
                  if triple.subject == main_subject and triple.object == rel_subject:
                      if triple.predicate in ["location", "cityServed"]:
                          sentence += ", " + connector + " " + rel_subject
                          connection_found = True
                          break
                      elif triple.predicate in ["capital", "country", "isPartOf"]:
                          sentence += ", " + rel_phrases[0].lower()
                          connection_found = True
                          break

              if not connection_found:
                  # No direct connection found, just add the phrase
                  sentence += ", " + rel_phrases[0].lower()

      return sentence + "."
